module RefModule (
    input wire clk,
    input wire reset,
    input wire load,
    input wire [63:0] load_value,
    output reg [63:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or posedge reset) begin
        if (reset) begin
            count <= 64'b0;
        end else if (load) begin
            count <= load_value;
        end else begin
            count <= count + 1;
        end
    end

endmodule
